// // This module implements a 3-bit linear voltage regulator control circuit that takes in a 3-bit input voltage (V_in) and produces a 3-bit output voltage (V_out) based on the following logic:
// - If V_in is greater than or equal to 3, set V_out to 3.
// - If V_in is less than 3 and greater than or equal to 6, set V_out to V_in.
// - If V_in is less than 6, set V_out to 6.
module voltage_regulator (
    input [2:0] V_in,
    output reg [2:0] V_out
);
    always @(*) begin
        if (V_in < 3)
            V_out = 3;
        else if (V_in >= 3 && V_in < 6)
            V_out = V_in;
        else
            V_out = 6;
    end
endmodule

